(function () {
    "use strict";

    const STORAGE_KEY = "huellitasBathRankingV1";
    const OWNER_KEY = "huellitasBathOwnerId";
    const BATH_IMAGE = "data:image/webp;base64,";
    const tools = {
        sponge: { label: "Esponja", icon: "\uD83E\uDDFD", helps: "lodo" },
        soap: { label: "Jabon", icon: "\uD83E\uDDFC", helps: "manchas" },
        water: { label: "Agua", icon: "\uD83D\uDCA7", helps: "espuma" },
        brush: { label: "Cepillo", icon: "\uD83E\uDEA5", helps: "pulguitas" },
        towel: { label: "Toalla", icon: "\uD83E\uDDFB", helps: "gotas" }
    };
    const spotMeta = {
        mud: { tool: "sponge", icon: "\uD83D\uDFE4", label: "Lodo", required: 2 },
        stain: { tool: "soap", icon: "\u2728", label: "Mancha", required: 1 },
        foam: { tool: "water", icon: "\uD83E\uDEE7", label: "Espuma", required: 1 },
        flea: { tool: "brush", icon: "\uD83D\uDC1E", label: "Pulguita", required: 1 },
        drop: { tool: "towel", icon: "\uD83D\uDCA7", label: "Gota", required: 1 }
    };
    let game = null;
    let recordsMode = "all";
    let pointerDown = false;
    let lastRubAt = 0;

    function onReady(callback) {
        if (document.readyState === "loading") {
            document.addEventListener("DOMContentLoaded", callback, { once: true });
        } else {
            callback();
        }
    }

    function loadStyles() {
        if (document.getElementById("huellitasBathChallengeCss")) {
            return;
        }
        const link = document.createElement("link");
        link.id = "huellitasBathChallengeCss";
        link.rel = "stylesheet";
        link.href = "huellitas-bath-challenge.css?v=20260629-bath-v1";
        document.head.appendChild(link);
    }

    function ownerId() {
        try {
            if (typeof getPlayer === "function") {
                const player = getPlayer();
                if (player && (player.id || player.email)) {
                    return String(player.id || player.email);
                }
            }
        } catch (error) {
            console.warn(error.message);
        }

        let id = localStorage.getItem(OWNER_KEY);
        if (!id) {
            id = "bath-" + Date.now().toString(36) + "-" + Math.random().toString(36).slice(2, 9);
            localStorage.setItem(OWNER_KEY, id);
        }
        return id;
    }

    function safeNickname(value) {
        const clean = String(value || "")
            .normalize("NFKC")
            .replace(/[^a-zA-Z0-9\u00C0-\u017F_. -]/g, "")
            .replace(/\s+/g, " ")
            .trim()
            .slice(0, 12);
        return ["admin", "moderador", "huellitas oficial"].includes(clean.toLowerCase()) ? "" : clean;
    }

    function readRecords() {
        try {
            const value = JSON.parse(localStorage.getItem(STORAGE_KEY) || "[]");
            return Array.isArray(value) ? value.filter(function (item) {
                return item && Number(item.cleanliness) === 100 && Number.isFinite(Number(item.time));
            }).slice(-100) : [];
        } catch (error) {
            return [];
        }
    }

    function writeRecords(records) {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(records.slice(-100)));
    }

    function formatTime(milliseconds) {
        const total = Math.max(0, Math.floor(Number(milliseconds || 0) / 10));
        const minutes = Math.floor(total / 6000);
        const seconds = Math.floor((total % 6000) / 100);
        const hundredths = total % 100;
        return String(minutes).padStart(2, "0") + ":" + String(seconds).padStart(2, "0") + "." + String(hundredths).padStart(2, "0");
    }

    function dateLabel(iso) {
        const value = new Date(iso);
        const today = new Date();
        if (value.toDateString() === today.toDateString()) {
            return "Hoy";
        }
        return value.toLocaleDateString("es-MX", { day: "2-digit", month: "short" });
    }

    function buildMarkup(panel) {
        panel.classList.add("bath-premium");
        panel.innerHTML = [
            '<div class="bath-premium-layout">',
                '<section class="bath-main" aria-labelledby="bathPremiumTitle">',
                    '<div class="bath-hero">',
                        '<div class="bath-hero-copy">',
                            '<span class="bath-kicker">HIGIENE</span>',
                            '<h2 id="bathPremiumTitle">Ba&ntilde;o <em>Express</em></h2>',
                            '<p>Limpia a tu mascota con rapidez. Quita lodo, gotas y pulguitas para mejorar su salud.</p>',
                        '</div>',
                        '<figure class="bath-illustration"><img src="' + BATH_IMAGE + '" alt="Perrito feliz disfrutando su ba&ntilde;o" draggable="false"></figure>',
                    '</div>',
                    '<div class="bath-stats" aria-live="polite">',
                        '<div><span>&#9201; Tiempo</span><strong id="cleanTimer">00:00.00</strong><small>/ 01:30</small></div>',
                        '<div><span>&#10024; Limpieza</span><strong id="cleanScore">0%</strong><small>Objetivo: 100%</small></div>',
                        '<div><span>&#11088; Combo</span><strong id="bathCombo">x0</strong><small id="bathComboNote">Listo</small></div>',
                    '</div>',
                    '<div class="bath-progress">',
                        '<div><span>Progreso de limpieza</span><strong id="bathProgressText">0%</strong></div>',
                        '<b><i id="bathProgressBar"></i></b>',
                    '</div>',
                    '<div class="bath-stage" id="cleanBoard" aria-label="Zona interactiva de limpieza">',
                        '<div class="bath-stage-grid" aria-hidden="true"></div>',
                        '<div class="bath-bubbles" aria-hidden="true"><i></i><i></i><i></i><i></i><i></i></div>',
                        '<div class="bath-pet-zone" data-bath-pet></div>',
                        '<div class="bath-spots" data-bath-spots></div>',
                        '<div class="bath-reaction" id="bathReaction">Elige una herramienta y comienza el ba&ntilde;o.</div>',
                    '</div>',
                    '<div class="bath-tool-panel">',
                        '<div class="bath-tool-heading"><strong>Elige tu herramienta</strong><span>Selecciona y frota sobre la suciedad correcta.</span></div>',
                        '<div class="bath-tools" role="toolbar" aria-label="Herramientas de limpieza">',
                            '<button type="button" data-bath-tool="sponge"><span>&#129533;</span><strong>Esponja</strong><small>Lodo</small></button>',
                            '<button type="button" data-bath-tool="soap"><span>&#129532;</span><strong>Jab&oacute;n</strong><small>Manchas</small></button>',
                            '<button type="button" data-bath-tool="water"><span>&#128167;</span><strong>Agua</strong><small>Espuma</small></button>',
                            '<button type="button" data-bath-tool="brush"><span>&#129701;</span><strong>Cepillo</strong><small>Pulguitas</small></button>',
                            '<button type="button" data-bath-tool="towel"><span>&#129531;</span><strong>Toalla</strong><small>Gotas</small></button>',
                        '</div>',
                    '</div>',
                    '<button class="bath-start" id="bathStartButton" type="button"><span aria-hidden="true">&#128062;</span> Iniciar limpieza</button>',
                    '<p class="bath-help">Llega al 100% combinando rapidez y precisi&oacute;n.</p>',
                '</section>',
                '<aside class="bath-ranking" aria-label="Clasificacion de Bano Express">',
                    '<div class="bath-ranking-tabs" role="tablist">',
                        '<button class="active" type="button" data-bath-records="all" role="tab" aria-selected="true">&#127942; Clasificaci&oacute;n</button>',
                        '<button type="button" data-bath-records="mine" role="tab" aria-selected="false">&#9201; Mis r&eacute;cords</button>',
                    '</div>',
                    '<div class="bath-ranking-title"><strong>Mejores ba&ntilde;os</strong><span>Reto r&aacute;pido</span></div>',
                    '<div class="bath-ranking-table" id="bathRankingTable"></div>',
                    '<div class="bath-ranking-footer">',
                        '<small>Menor tiempo y mejor combo ganan.</small>',
                        '<button type="button" id="bathDeleteRecords">&#128465; Borrar mis r&eacute;cords</button>',
                    '</div>',
                '</aside>',
            '</div>',
            '<div class="bath-result-modal" id="bathResultModal" hidden>',
                '<div class="bath-result-backdrop" data-bath-close></div>',
                '<section class="bath-result-card" role="dialog" aria-modal="true" aria-labelledby="bathResultTitle">',
                    '<button class="bath-result-close" type="button" data-bath-close aria-label="Cerrar resultado">&times;</button>',
                    '<div class="bath-result-sparkles" aria-hidden="true"><i></i><i></i><i></i><i></i><i></i></div>',
                    '<div class="bath-result-visual"><img src="' + BATH_IMAGE + '" alt="" draggable="false"><span>&#127942;</span></div>',
                    '<h2 id="bathResultTitle">&iexcl;Ba&ntilde;o completado!</h2>',
                    '<p class="bath-result-subtitle">Tu mascota est&aacute; limpia y feliz.</p>',
                    '<div class="bath-result-stats">',
                        '<div><span>Tiempo</span><strong id="bathFinalTime">00:00.00</strong></div>',
                        '<div><span>Limpieza</span><strong>100%</strong></div>',
                        '<div><span>Mejor combo</span><strong id="bathFinalCombo">x0</strong></div>',
                    '</div>',
                    '<p class="bath-record-note" id="bathRecordNote"></p>',
                    '<label for="bathNickname">Tu apodo</label>',
                    '<div class="bath-nickname-row"><input id="bathNickname" type="text" maxlength="12" autocomplete="nickname" placeholder="Escribe tu apodo..."><span id="bathNicknameCount">0/12</span></div>',
                    '<p class="bath-nickname-error" id="bathNicknameError" role="alert"></p>',
                    '<div class="bath-result-actions">',
                        '<button class="bath-save-result" id="bathSaveResult" type="button">&#127942; Guardar resultado</button>',
                        '<button class="bath-play-again" id="bathPlayAgain" type="button">&#8635; Jugar otra vez</button>',
                    '</div>',
                '</section>',
            '</div>'
        ].join("");
    }

    function elements() {
        return {
            board: document.getElementById("cleanBoard"),
            spots: document.querySelector("[data-bath-spots]"),
            pet: document.querySelector("[data-bath-pet]"),
            timer: document.getElementById("cleanTimer"),
            score: document.getElementById("cleanScore"),
            combo: document.getElementById("bathCombo"),
            comboNote: document.getElementById("bathComboNote"),
            progress: document.getElementById("bathProgressBar"),
            progressText: document.getElementById("bathProgressText"),
            reaction: document.getElementById("bathReaction"),
            start: document.getElementById("bathStartButton"),
            modal: document.getElementById("bathResultModal"),
            finalTime: document.getElementById("bathFinalTime"),
            finalCombo: document.getElementById("bathFinalCombo"),
            recordNote: document.getElementById("bathRecordNote"),
            nickname: document.getElementById("bathNickname"),
            nicknameCount: document.getElementById("bathNicknameCount"),
            nicknameError: document.getElementById("bathNicknameError"),
            ranking: document.getElementById("bathRankingTable")
        };
    }

    function createSpots() {
        const types = ["mud", "mud", "mud", "stain", "stain", "flea", "flea", "drop", "drop"];
        const positions = [
            [17, 27], [70, 61], [29, 70], [74, 28], [47, 18],
            [20, 55], [80, 48], [41, 62], [60, 73]
        ];

        return types.map(function (type, index) {
            const meta = spotMeta[type];
            return {
                id: index,
                type: type,
                x: positions[index][0] + (Math.random() * 4 - 2),
                y: positions[index][1] + (Math.random() * 4 - 2),
                remaining: meta.required,
                complete: false
            };
        });
    }

    function totalStepsFor(spots) {
        return spots.reduce(function (total, spot) {
            if (spot.type === "mud") {
                return total + 2;
            }
            if (spot.type === "stain") {
                return total + 2;
            }
            return total + 1;
        }, 0);
    }

    function freshGame() {
        const spots = createSpots();
        return {
            active: false,
            selectedTool: "sponge",
            spots: spots,
            totalSteps: totalStepsFor(spots),
            completedSteps: 0,
            combo: 0,
            bestCombo: 0,
            elapsed: 0,
            startedAt: 0,
            frame: null,
            rewarded: false
        };
    }

    function petMarkup() {
        if (typeof getMiniPetSpriteMarkup === "function") {
            return getMiniPetSpriteMarkup("bath-pet-sprite");
        }
        return '<span class="bath-pet-fallback" aria-label="Perrito pixel art"></span>';
    }

    function cleanliness() {
        return Math.min(100, Math.round((game.completedSteps / game.totalSteps) * 100));
    }

    function renderStats() {
        const el = elements();
        const value = cleanliness();
        el.timer.textContent = formatTime(game.elapsed);
        el.score.textContent = value + "%";
        el.combo.textContent = "x" + game.combo;
        el.comboNote.textContent = game.combo >= 8 ? "Increible" : game.combo >= 4 ? "Muy bien" : game.combo ? "Sigue asi" : "Listo";
        el.progress.style.width = value + "%";
        el.progressText.textContent = value + "%";
        el.board.style.setProperty("--bath-clean", value + "%");
        el.board.classList.toggle("is-clean", value === 100);
    }

    function renderToolState() {
        document.querySelectorAll("[data-bath-tool]").forEach(function (button) {
            const active = button.dataset.bathTool === game.selectedTool;
            button.classList.toggle("active", active);
            button.setAttribute("aria-pressed", active ? "true" : "false");
        });
        elements().board.dataset.tool = game.selectedTool;
    }

    function renderSpotElement(spot) {
        const meta = spotMeta[spot.type];
        const button = document.createElement("button");
        button.type = "button";
        button.className = "bath-spot bath-spot-" + spot.type + (spot.remaining < meta.required ? " partly-clean" : "");
        button.dataset.spotId = String(spot.id);
        button.style.left = spot.x + "%";
        button.style.top = spot.y + "%";
        button.setAttribute("aria-label", meta.label + ". Usa " + tools[meta.tool].label + ".");
        button.textContent = meta.icon;

        button.addEventListener("pointerdown", function (event) {
            event.preventDefault();
            pointerDown = true;
            cleanSpot(spot.id, button);
        });
        button.addEventListener("pointerenter", function () {
            if (pointerDown) {
                cleanSpot(spot.id, button);
            }
        });
        button.addEventListener("click", function (event) {
            event.preventDefault();
            cleanSpot(spot.id, button);
        });
        return button;
    }

    function renderSpots() {
        const target = elements().spots;
        target.replaceChildren();
        game.spots.filter(function (spot) {
            return !spot.complete;
        }).forEach(function (spot) {
            target.appendChild(renderSpotElement(spot));
        });
    }

    function setReaction(message, mood) {
        const el = elements();
        el.reaction.textContent = message;
        el.board.dataset.mood = mood || "calm";
        window.clearTimeout(setReaction.timer);
        setReaction.timer = window.setTimeout(function () {
            el.board.dataset.mood = game.active ? "ready" : "calm";
        }, 650);
    }

    function expectedMessage(spot) {
        const meta = spotMeta[spot.type];
        return "Prueba con " + tools[meta.tool].label + " para " + meta.label.toLowerCase() + ".";
    }

    function correctInteraction(spot, spotElement) {
        const meta = spotMeta[spot.type];
        game.combo += 1;
        game.bestCombo = Math.max(game.bestCombo, game.combo);
        game.completedSteps += 1;
        spot.remaining -= 1;

        if (typeof playGameSound === "function") {
            playGameSound("good");
        }

        spotElement.classList.add("cleaned");
        setReaction(game.combo >= 5 ? "Gran combo. Tu perrito esta feliz." : tools[game.selectedTool].label + " funciono.", "happy");

        if (spot.type === "stain" && spot.remaining <= 0) {
            spot.type = "foam";
            spot.remaining = 1;
        } else if (spot.remaining <= 0) {
            spot.complete = true;
        }

        renderStats();
        window.setTimeout(renderSpots, 150);

        if (cleanliness() >= 100) {
            window.setTimeout(completeGame, 220);
        }
    }

    function cleanSpot(id, spotElement) {
        if (!game.active) {
            setReaction("Primero inicia la limpieza.", "calm");
            return;
        }

        const now = performance.now();
        if (now - lastRubAt < 85) {
            return;
        }
        lastRubAt = now;

        const spot = game.spots.find(function (item) {
            return item.id === Number(id);
        });
        if (!spot || spot.complete) {
            return;
        }

        const meta = spotMeta[spot.type];
        if (meta.tool !== game.selectedTool) {
            game.combo = 0;
            if (typeof playGameSound === "function") {
                playGameSound("bad");
            }
            spotElement.classList.add("wrong-tool");
            setReaction(expectedMessage(spot), "oops");
            renderStats();
            window.setTimeout(function () {
                spotElement.classList.remove("wrong-tool");
            }, 300);
            return;
        }

        correctInteraction(spot, spotElement);
    }

    function updateClock(now) {
        if (!game.active) {
            return;
        }
        game.elapsed = now - game.startedAt;
        elements().timer.textContent = formatTime(game.elapsed);
        game.frame = window.requestAnimationFrame(updateClock);
    }

    function rewardPet() {
        if (game.rewarded) {
            return;
        }
        game.rewarded = true;
        try {
            if (typeof premiarJuego === "function") {
                premiarJuego("Bano perfecto. Tu mascota esta limpia y feliz.", 18, 16, { health: 12, happy: 6, bond: 4 });
            } else if (typeof saveState === "function") {
                saveState();
            }
        } catch (error) {
            console.warn("No se pudo aplicar la recompensa del bano:", error.message);
        }
    }

    function bestPreviousTime() {
        const records = readRecords();
        return records.length ? Math.min.apply(null, records.map(function (item) {
            return Number(item.time);
        })) : Infinity;
    }

    function completeGame() {
        if (!game.active) {
            return;
        }
        game.elapsed = performance.now() - game.startedAt;
        game.active = false;
        pointerDown = false;
        window.cancelAnimationFrame(game.frame);
        game.frame = null;
        game.completedSteps = game.totalSteps;
        renderStats();
        renderSpots();
        rewardPet();

        const el = elements();
        const isRecord = game.elapsed < bestPreviousTime();
        el.start.innerHTML = '<span aria-hidden="true">&#8635;</span> Jugar otra vez';
        el.start.classList.remove("running");
        el.finalTime.textContent = formatTime(game.elapsed);
        el.finalCombo.textContent = "x" + game.bestCombo;
        el.recordNote.textContent = isRecord ? "Nuevo record en este dispositivo." : "Bano perfecto. Sigue mejorando tu tiempo.";
        el.nickname.value = "";
        el.nicknameCount.textContent = "0/12";
        el.nicknameError.textContent = "";
        el.modal.hidden = false;
        document.body.classList.add("bath-modal-open");
        setReaction("Limpio, feliz y listo para jugar.", "complete");
        window.setTimeout(function () {
            el.nickname.focus();
        }, 120);
    }

    function startGame() {
        if (game && game.frame) {
            window.cancelAnimationFrame(game.frame);
        }
        game = freshGame();
        game.active = true;
        game.startedAt = performance.now();
        pointerDown = false;

        const el = elements();
        el.modal.hidden = true;
        document.body.classList.remove("bath-modal-open");
        el.pet.innerHTML = petMarkup();
        el.start.innerHTML = '<span aria-hidden="true">&#129533;</span> Limpiando...';
        el.start.classList.add("running");
        renderToolState();
        renderSpots();
        renderStats();
        setReaction("Busca lodo y frota con la esponja.", "ready");
        game.frame = window.requestAnimationFrame(updateClock);
    }

    function closeModal() {
        const modal = elements().modal;
        if (modal) {
            modal.hidden = true;
        }
        document.body.classList.remove("bath-modal-open");
    }

    function sortedRecords() {
        const id = ownerId();
        return readRecords().filter(function (item) {
            return recordsMode === "all" || item.owner === id;
        }).sort(function (a, b) {
            return Number(a.time) - Number(b.time) || Number(b.combo) - Number(a.combo);
        }).slice(0, 10);
    }

    function addCell(row, text, className) {
        const cell = document.createElement("span");
        cell.className = className || "";
        cell.textContent = text;
        row.appendChild(cell);
    }

    function renderRanking() {
        const target = elements().ranking;
        if (!target) {
            return;
        }
        target.replaceChildren();

        const head = document.createElement("div");
        head.className = "bath-rank-row bath-rank-head";
        ["#", "Jugador", "Tiempo", "Limpieza", "Combo", "Fecha"].forEach(function (label) {
            addCell(head, label);
        });
        target.appendChild(head);

        const records = sortedRecords();
        if (!records.length) {
            const empty = document.createElement("div");
            empty.className = "bath-ranking-empty";
            empty.textContent = recordsMode === "mine"
                ? "Aun no guardas banos. Tu siguiente reto puede ser el primero."
                : "Completa un bano al 100% para abrir la clasificacion.";
            target.appendChild(empty);
            return;
        }

        records.forEach(function (record, index) {
            const row = document.createElement("div");
            row.className = "bath-rank-row";
            if (record.owner === ownerId()) {
                row.classList.add("is-mine");
            }
            const place = index + 1;
            addCell(row, place < 4 ? ["\uD83E\uDD47", "\uD83E\uDD48", "\uD83E\uDD49"][place - 1] : String(place), "bath-rank-place");
            addCell(row, record.nickname, "bath-rank-name");
            addCell(row, formatTime(record.time), "bath-rank-time");
            addCell(row, "100%");
            addCell(row, "x" + record.combo);
            addCell(row, dateLabel(record.date));
            target.appendChild(row);
        });
    }

    function saveResult() {
        const el = elements();
        const nickname = safeNickname(el.nickname.value);
        if (!nickname) {
            el.nicknameError.textContent = "Escribe un apodo valido de hasta 12 caracteres.";
            el.nickname.focus();
            return;
        }

        const records = readRecords();
        records.push({
            id: "bath-" + Date.now().toString(36) + "-" + Math.random().toString(36).slice(2, 7),
            owner: ownerId(),
            nickname: nickname,
            time: Math.round(game.elapsed),
            cleanliness: 100,
            combo: game.bestCombo,
            date: new Date().toISOString()
        });
        writeRecords(records);
        setRecordsMode("all");
        closeModal();
    }

    function setRecordsMode(mode) {
        recordsMode = mode === "mine" ? "mine" : "all";
        document.querySelectorAll("[data-bath-records]").forEach(function (button) {
            const active = button.dataset.bathRecords === recordsMode;
            button.classList.toggle("active", active);
            button.setAttribute("aria-selected", active ? "true" : "false");
        });
        renderRanking();
    }

    function deleteMyRecords() {
        const mine = ownerId();
        if (!readRecords().some(function (item) { return item.owner === mine; })) {
            return;
        }
        if (!window.confirm("Borrar tus records de Bano Express en este dispositivo?")) {
            return;
        }
        writeRecords(readRecords().filter(function (item) {
            return item.owner !== mine;
        }));
        renderRanking();
    }

    function bindControls() {
        const el = elements();

        document.querySelectorAll("[data-bath-tool]").forEach(function (button) {
            button.addEventListener("click", function () {
                game.selectedTool = button.dataset.bathTool;
                renderToolState();
                setReaction(tools[game.selectedTool].label + " lista para " + tools[game.selectedTool].helps + ".", "ready");
            });
        });

        el.board.addEventListener("pointerdown", function () {
            pointerDown = true;
        });
        window.addEventListener("pointerup", function () {
            pointerDown = false;
        });
        el.board.addEventListener("pointermove", function (event) {
            if (!pointerDown || !game.active) {
                return;
            }
            const found = document.elementFromPoint(event.clientX, event.clientY);
            const spot = found && found.closest && found.closest(".bath-spot");
            if (spot) {
                cleanSpot(spot.dataset.spotId, spot);
            }
        });

        el.start.addEventListener("click", startGame);
        document.querySelectorAll("[data-bath-close]").forEach(function (button) {
            button.addEventListener("click", closeModal);
        });
        document.getElementById("bathSaveResult").addEventListener("click", saveResult);
        document.getElementById("bathPlayAgain").addEventListener("click", function () {
            closeModal();
            startGame();
        });
        document.getElementById("bathDeleteRecords").addEventListener("click", deleteMyRecords);
        document.querySelectorAll("[data-bath-records]").forEach(function (button) {
            button.addEventListener("click", function () {
                setRecordsMode(button.dataset.bathRecords);
            });
        });

        el.nickname.addEventListener("input", function () {
            const value = safeNickname(el.nickname.value);
            el.nicknameCount.textContent = value.length + "/12";
            el.nicknameError.textContent = "";
        });
        el.nickname.addEventListener("keydown", function (event) {
            if (event.key === "Enter") {
                event.preventDefault();
                saveResult();
            }
        });
        document.addEventListener("keydown", function (event) {
            if (event.key === "Escape" && !el.modal.hidden) {
                closeModal();
            }
        });
    }

    function enhance() {
        const panel = document.getElementById("game-clean");
        if (!panel || panel.dataset.bathPremium === "true") {
            return;
        }

        panel.dataset.bathPremium = "true";
        loadStyles();
        buildMarkup(panel);
        game = freshGame();
        elements().pet.innerHTML = petMarkup();
        renderToolState();
        renderSpots();
        renderStats();
        renderRanking();
        bindControls();

        window.iniciarLimpiezaExpress = startGame;
        window.renderCleanBoard = function () {};
        window.limpiarMancha = function (id) {
            const spot = document.querySelector('[data-spot-id="' + id + '"]');
            cleanSpot(id, spot);
        };
        window.finalizarLimpiezaExpress = completeGame;
    }

    onReady(enhance);
    window.addEventListener("pagehide", function () {
        if (game && game.frame) {
            window.cancelAnimationFrame(game.frame);
        }
    });
})();